Sure, here's an example of Rust code that sorts an array of integers using a merge sort algorithm:

```
fn merge_sort<T>(mut arr: Vec<T>) -> Vec<T>
where
    T: PartialOrd + Clone,
{
    if arr.len() <= 1 {
        return arr;
    }
    let mid = arr.len() / 2;
    let left = merge_sort(arr[..mid].to_vec());
    let right = merge_sort(arr[mid..].to_vec());
    merge(left, right)
}

fn merge<T: PartialOrd + Clone>(left: Vec<T>, right: Vec<T>) -> Vec<T> {
    let mut res = Vec::new();
    let mut left_idx = 0;
    let mut right_idx = 0;
    while left_idx < left.len() && right_idx < right.len() {
        if left[left_idx] < right[right_idx] {
            res.push(left[left_idx].clone());
            left_idx += 1;
        } else {
            res.push(right[right_idx].clone());
            right_idx += 1;
        }
    }
    while left_idx < left.len() {
        res.push(left[left_idx].clone());
        left_idx += 1;
    }
    while right_idx < right.len() {
        res.push(right[right_idx].clone());
        right_idx += 1;
    }
    res
}

fn main() {
    let arr = vec![4, 65, 2, -31, 0, 99, 2, 83, 782, 1];
    let sorted_arr = merge_sort(arr.clone());
    println!("{:?}", sorted_arr);
}
```
